package main

import (
	"context"
	"fmt"
	"log"

	datav1 "github.com/open-policy-agent/eopa/proto/gen/go/eopa/data/v1"

	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/protobuf/types/known/structpb"
)

func main() {
	ctx := context.Background()
	// Connect to the Enterprise OPA instance.
	conn, err := grpc.Dial("localhost:50555", grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		log.Fatalf("failed to dial the EOPA server: %v", err)
	}
	defer conn.Close()
	client := datav1.NewDataServiceClient(conn)

	// Prepare a normal gRPC Data Get request:
	s, _ := structpb.NewStruct(map[string]interface{}{
		"jwt": "eyJhbGciOiJQUzM4NCIsImN0eSI6InZwIiwiZXhwIjoxNzk4Mzc0NTA3MzU5LCJpYXQiOjE3NjY4Mzg1MDczNTksImlzcyI6ImRpZDp3ZWI6dmFsaWRhdGUucG9zZWRpby5jb20iLCJraWQiOiJkaWQ6d2ViOnZhbGlkYXRlLnBvc2VkaW8uY29tIzIwMjUtdjEiLCJ0eXAiOiJ2cCtqd3QifQ..XsciACa5kk3tmCXA1AAUfOyr811SEFTqqVDfO6O7EetVLKu_Kr5SF01-kF5iuxBqKjx4rrh5p1IDr0qcov5oQW4xL1losLufb8mz6ijSR5DAIpQ80TFbgYMji_d2CxXN7oENJSzDFejZ1OqHTijMTSFDQiFSXZ2S7DnjoEJOEDwnZVyANowdlLBUulMQ3qafstI9pbWKgx-LNqMdTXVeda8oD4_9A9HX353zxafdHaRzSXqiRLWTDdHd5YLTKbBtxm7yvQMuD-opCxGUUsIlw7t-2Iwes-liP8RdMIRsztXY5fNNPmKhFVeNyZQVg1M3bJf_0ILs88fQynKjGVldpg",
	})
	doc := &datav1.InputDocument{Document: s}
	// Send unary gRPC message, and block until response arrives.
	resp, err := client.GetData(ctx, &datav1.GetDataRequest{Path: "verify/legalPerson", Input: doc})
	if err != nil {
		log.Fatalf("GetData failed: %v", err)
	}
	resultDoc := resp.GetResult()
	path := resultDoc.GetPath()
	allowed := resultDoc.GetDocument()
	fmt.Println(path, allowed)
}
